1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - base premiums", () => {
6	    it("empty item list yields premium of 5 G (processing fee only)", () => {
7	      const result = runScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote", items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("single plain sword yields 100 G base + 10 G first insurance + 5 G fee = 115 G for newcomer");
14	    it.todo("single plain amulet yields 60 G base + 6 G first insurance + 5 G fee = 71 G for newcomer");
15	    it.todo("single plain staff yields 80 G base + 8 G first insurance + 5 G fee = 93 G for newcomer");
16	    it.todo("single plain potion yields 40 G base + 4 G first insurance + 5 G fee = 49 G for newcomer");
17	    it.todo("single rune yields 25 G base + 3 G first insurance (rounded up) + 5 G fee = 33 G for newcomer");
18	  });
19	
20	  describe("quote - component building blocks", () => {
21	    it.todo("2 runes yields 50 G base premium (no block)");
22	    it.todo("3 runes yields 60 G base premium (block applies)");
23	    it.todo("4 runes yields 100 G base premium (no block)");
24	    it.todo("3 runes + 3 moonstones yields 120 G base premium (two separate blocks)");
25	  });
26	
27	  describe("quote - item modifiers", () => {
28	    it.todo("cursed sword adds 50% surcharge on that item's base premium");
29	    it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
30	    it.todo("sword with enchantment 4 does not add high-enchantment surcharge");
31	    it.todo("cursed sword with enchantment 5 stacks both surcharges");
32	  });
33	
34	  describe("quote - policy modifiers", () => {
35	    it.todo("customer with 2 years receives 20% loyalty discount on policy base");
36	    it.todo("first insurance surcharge applies per item (10% of item base)");
37	    it.todo("second contract gets 15% follow-up discount on policy base");
38	  });
39	
40	  describe("quote - integration examples", () => {
41	    it.todo("newcomer with cursed steel sword (enchantment 3) yields premium 165 G");
42	    it.todo("3-year customer's second quote of cursed sword enchantment 7 yields premium 160 G");
43	    it.todo("cursed sword + plain amulet for newcomer yields 210 G before fee/first-insurance modifiers per spec");
44	  });
45	
46	  describe("quote - rounding", () => {
47	    it.todo("premium that yields fractional amount is rounded up in MHPCO's favor");
48	  });
49	
50	  describe("claim - base payouts", () => {
51	    it.todo("regular steel sword enchantment 3 with 500 G damage yields payout 400 G");
52	    it.todo("rune with 200 G damage yields payout 100 G");
53	    it.todo("dragon-material sword enchantment 8 with 1000 G damage yields payout 400 G (50% then deductible)");
54	    it.todo("dragon-material sword enchantment 5 with 800 G damage yields payout 700 G (full minus deductible)");
55	    it.todo("steel sword enchantment 9 with 1000 G damage yields payout 400 G (50% then deductible)");
56	  });
57	
58	  describe("claim - multiple damages", () => {
59	    it.todo("dragon attack on sword (500 G) and amulet (300 G) yields payout 600 G (deductible per item)");
60	    it.todo("two swords in policy, both damaged yields per-item deductible applied");
61	  });
62	
63	  describe("claim - rounding", () => {
64	    it.todo("payout that yields fractional amount is rounded down in MHPCO's favor");
65	  });
66	
67	  describe("error handling", () => {
68	    it.todo("quote with unknown item type throws an error");
69	    it.todo("claim referencing item not in policy throws an error");
70	    it.todo("claim with negative damage amount throws an error");
71	    it.todo("claim with more damages of a type than insured throws an error");
72	  });
73	});
